            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__status_active),
              selected: params.isDeletionScheduled == false,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(isDeletionScheduled: false);
              },
            ),
            FilterChip(
              label: Text(
                  context.l10n.super_admin_team_filter__status_deletion_scheduled),
              selected: params.isDeletionScheduled == true,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(isDeletionScheduled: true);
              },
            ),
          ],
        ),
      ],
    );
  }

  Widget _buildPlanSection(
    BuildContext context,
    WidgetRef ref,
    ThemeData theme,
    TeamSearchFilterParameters params,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__plan,
          style: theme.textTheme.titleSmall,
