          ),
          child: Column(
            children: [
              // Handle
              Container(
                margin: const EdgeInsets.symmetric(vertical: 12),
                width: 40,
                height: 4,
                decoration: BoxDecoration(
                  color: theme.colorScheme.onSurfaceVariant.withOpacity(0.4),
                  borderRadius: BorderRadius.circular(2),
                ),
              ),
              // Title
              Padding(
                padding: const EdgeInsets.symmetric(horizontal: 16),
                child: Row(
                  children: [
                    Expanded(
                      child: Text(
                        context.l10n.super_admin_team_filter__title,
                        style: theme.textTheme.titleLarge,
                      ),
                    ),
                    TextButton(
                      onPressed: () {
                        ref
                            .read(teamSearchFilterParametersNotifierProvider
                                .notifier)
                            .clearFilters();
                        Navigator.pop(context);
                      },
                      child: Text(context.l10n.super_admin_team_filter__reset),
                    ),
                  ],
                ),
              ),
              const Divider(),
              // Filter content
              Expanded(
                child: ListView(
                  controller: scrollController,
                  padding: const EdgeInsets.all(16),
                  children: [
                    _buildSortSection(context, ref, theme, params),
                    const Gap(24),
                    _buildTeamTypeSection(context, ref, theme, params),
                    const Gap(24),
                    _buildStatusSection(context, ref, theme, params),
                    const Gap(24),
                    _buildPlanSection(context, ref, theme, params),
                    const Gap(24),
                    _buildExpirySection(context, ref, theme, params),
                  ],
                ),
              ),
              // Apply button
              SafeArea(
                child: Padding(
                  padding: const EdgeInsets.all(16),
                  child: SizedBox(
                    width: double.infinity,
