          ref,
          context.l10n.super_admin_team_filter__sort_plan_end_desc,
          TeamSearchRequestOrderBy.teamPlanEndDate,
          true,
          params.orderBy == TeamSearchRequestOrderBy.teamPlanEndDate &&
              params.isOrderDesc == true,
        ),
      ],
    );
  }

  Widget _buildSortOption(
    BuildContext context,
    WidgetRef ref,
    String label,
    TeamSearchRequestOrderBy orderBy,
    bool isDesc,
    bool isSelected,
  ) {
    return RadioListTile<bool>(
      title: Text(label),
      value: true,
