    TeamSearchFilterParameters params,
  ) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          context.l10n.super_admin_team_filter__team_type,
          style: theme.textTheme.titleSmall,
        ),
        const Gap(12),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            FilterChip(
              label: Text(context.l10n.super_admin_team_filter__all),
              selected: params.teamTypes == null || params.teamTypes!.isEmpty,
              onSelected: (_) {
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(teamTypes: null);
              },
            ),
            FilterChip(
              label: Text(context.l10n.team_type__single),
              selected: params.teamTypes?.contains(TeamType.single) ?? false,
              onSelected: (selected) {
                final newTypes = selected ? [TeamType.single] : <TeamType>[];
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(teamTypes: newTypes.isEmpty ? null : newTypes);
              },
            ),
            FilterChip(
              label: Text(context.l10n.team_type__multiple),
              selected: params.teamTypes?.contains(TeamType.multiple) ?? false,
              onSelected: (selected) {
                final newTypes =
                    selected ? [TeamType.multiple] : <TeamType>[];
                ref
                    .read(teamSearchFilterParametersNotifierProvider.notifier)
                    .updateFilters(teamTypes: newTypes.isEmpty ? null : newTypes);
              },
            ),
          ],
        ),
      ],
    );
  }

  Widget _buildStatusSection(
