                    TextButton(
                      onPressed: () {
                        // ローカル状態をリセット
                        localParams.value = const TeamSearchFilterParameters();
                      },
                      child: Text(context.l10n.super_admin_team_filter__reset),
                    ),
                  ],
                ),
              ),
              const Divider(),
              // Filter content
              Expanded(
                child: ListView(
                  controller: scrollController,
                  padding: const EdgeInsets.all(16),
                  children: [
                    _buildSortSection(context, theme, localParams),
                    const Gap(24),
                    _buildTeamTypeSection(context, theme, localParams),
                    const Gap(24),
                    _buildStatusSection(context, theme, localParams),
                    const Gap(24),
                    _buildPlanSection(context, theme, localParams),
                    const Gap(24),
                    _buildExpirySection(context, theme, localParams),
